          dec = PGTYPESdecimal_new();
          /* 将一个decimal类型的变量转换成numeric */
          r = PGTYPESnumeric_to_decimal(num, dec);
          if (r) check_errno();
          printf("num[%d,11]: - (r: %d)\n", i, r);
          if (r == 0)
          {
              /* 将一个decimal类型的变量转换成numeric */
              r = PGTYPESnumeric_from_decimal(dec, nin);
              if (r) check_errno();
